starterCode.css:
.grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 8px; max-width: 400px;
  /* Try both: grid-auto-flow: row vs column */
}
.grid > div {
  background: #e0e0e0; padding: 20px;
  text-align: center; border-radius: 4px;
}

.gallery {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 8px; max-width: 600px;
  /* Add grid-auto-flow: dense */
  grid-auto-rows: 80px;
}

.gallery > div {
  background: #f0f0f0; padding: 20px;
  border-radius: 4px; text-align: center;
  display: flex; align-items: center; justify-content: center;
}

.span2 { grid-column: span 2; background: #6c5ce7; color: white; }

solution.css:
.gallery { display: grid; grid-template-columns: repeat(4, 1fr); gap: 8px; max-width: 600px; grid-auto-flow: dense; grid-auto-rows: 80px; }
.gallery > div { background: #f0f0f0; padding: 20px; border-radius: 4px; text-align: center; display: flex; align-items: center; justify-content: center; }
.span2 { grid-column: span 2; background: #6c5ce7; color: white; }

