solution.css:
.portfolio { display: grid; grid-template-columns: repeat(4, 1fr); gap: 10px; max-width: 800px; grid-auto-flow: dense; grid-auto-rows: 100px; }
.portfolio > div { background: #2d2d44; color: #eee; padding: 20px; border-radius: 8px; text-align: center; display: flex; align-items: center; justify-content: center; font-weight: bold; }
.big { grid-column: span 2; grid-row: span 2; background: #6c5ce7; }
.wide { grid-column: span 2; background: #e17055; }
.tall { grid-row: span 2; background: #00cec9; color: #1a1a2e; }
